export function findAudioReferences(filter = {}, limit = 20) {
  const entries = AUDIO_REFERENCE_CATALOG.filter(entry => {
    return Object.entries(filter).every(([key, value]) => {
      if (value == null || value === '') return true;
      return entry[key] === value || entry.filter?.[key] === value;
    });
  });
  return entries.slice(0, limit);
}

export function findTtsResources(filter = {}, limit = 20) {
  const entries = TTS_RESOURCE_CATALOG.filter(entry => {
    return Object.entries(filter).every(([key, value]) => {
      if (value == null || value === '') return true;
      return entry[key] === value || entry.filter?.[key] === value;
    });
  });
  return entries.slice(0, limit);
}

export function resolveAssetUrl(entry, baseUrl = import.meta?.url ? new URL('..', import.meta.url).href : './') {
  if (!entry?.localPath) return null;
  return new URL(entry.localPath, baseUrl).href;
}

export function summarizeReferencePool() {
  const bySource = new Map();
  for (const entry of AUDIO_REFERENCE_CATALOG) {
    bySource.set(entry.source, (bySource.get(entry.source) || 0) + 1);
  }
  return [...bySource.entries()].map(([source, count]) => ({ source, count }));
}
